     * unique transaction id), for the same fresh-per-run reason as [`Self::presentation_request`].
     */override fun `paymentRequest`(`nonce`: kotlin.ULong): kotlin.ByteArray {
            return FfiConverterByteArray.lift(
    callWithPointer {
    uniffiRustCall() { _status ->
    UniffiLib.INSTANCE.uniffi_wallet_core_fn_method_demowallet_payment_request(
        it, FfiConverterULong.lower(`nonce`),_status)
