     * `nonce`. A persistent wallet engine records used nonces (replay protection), so each new
     * presentation must carry a fresh one — this lets the shell mint one per run.
     */override fun `presentationRequest`(`nonce`: kotlin.ULong): kotlin.ByteArray {
            return FfiConverterByteArray.lift(
    callWithPointer {
    uniffiRustCall() { _status ->
    UniffiLib.INSTANCE.uniffi_wallet_core_fn_method_demowallet_presentation_request(
        it, FfiConverterULong.lower(`nonce`),_status)
