/**
 * @suppress
 */
public object FfiConverterTypeDemoWallet: FfiConverter<DemoWallet, Pointer> {

    override fun lower(value: DemoWallet): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): DemoWallet {
        return DemoWallet(value)
    }

    override fun read(buf: ByteBuffer): DemoWallet {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: DemoWallet) = 8UL

    override fun write(value: DemoWallet, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}


