            FfiConverterLong.write(value.`epoch`, buf)
            FfiConverterByteArray.write(value.`trustList`, buf)
            FfiConverterByteArray.write(value.`operatorPublicKey`, buf)
            FfiConverterByteArray.write(value.`devicePublicKey`, buf)
            FfiConverterByteArray.write(value.`wuaJwt`, buf)
            FfiConverterByteArray.write(value.`walletProviderPublicKey`, buf)
            FfiConverterSequenceByteArray.write(value.`issuerCertChain`, buf)
            FfiConverterString.write(value.`issuerId`, buf)
            FfiConverterByteArray.write(value.`offer`, buf)
            FfiConverterString.write(value.`pidCredentialCompact`, buf)
            FfiConverterString.write(value.`mdlCredentialCompact`, buf)
            FfiConverterString.write(value.`passportCredentialCompact`, buf)
            FfiConverterString.write(value.`nidCredentialCompact`, buf)
            FfiConverterString.write(value.`germanIdCredentialCompact`, buf)
            FfiConverterString.write(value.`mdlMdocCredential`, buf)
    }
}





